const Dev1 = "ASSET_ID_START_MET_36 "  // CH01
const Dev2 = "ASSET_ID_START_MET_36 "  // CH02

const HEADER_LEN = 3

// Volgorde = volgorde van AT+COMMANDs
const CHANNELS = [
    { id: 4200, scale: true },  // CMD1: Total system power (W → kW)
    { id: 4300, scale: true },  // CMD2: Total system VAr (VAr → kVAr)
    { id: 4600, scale: false },  // CMD3: Import active energy (kWh)
    { id: 4500, scale: false },  // CMD4: Export active energy (kWh)
    { id: 4200, scale: true },  // CMD5: Total system power CH02
    { id: 4300, scale: true },  // CMD6: Total system VAr CH02
    { id: 4600, scale: false },  // CMD7: Import active energy CH02
    { id: 4500, scale: false },  // CMD8: Export active energy CH02
]

var buf = (typeof msg.payload === "string")
    ? Buffer.from(msg.payload, "base64")
    : msg.payload

if (!Buffer.isBuffer(buf) || buf.length < HEADER_LEN + 4) {
    node.error("Invalid payload - te kort", msg)
    return null
}

const battery = (((buf[0] << 8) | buf[1]) & 0x7fff) / 1000
const ts = msg.time ? new Date(msg.time).toISOString() : new Date().toISOString()

function readF(off) {
    if (off + 4 > buf.length) return null
    const v = buf.readFloatBE(off)
    if (!isFinite(v)) return null
    return Math.round(v * 1000) / 1000
}

// 8 floats uitlezen, graceful bij kortere buffer
const values = []
for (let i = 0; i < 8; i++) {
    const off = HEADER_LEN + i * 4
    values.push(off + 4 <= buf.length ? readF(off) : null)
}

function buildDevice(dev, vals, chStart) {
    const md = []

    for (let i = 0; i < 4; i++) {
        const ch = CHANNELS[chStart + i]
        let val = vals[i]
        if (val == null) continue
        if (ch.scale) val = Math.round((val / 1000) * 1000) / 1000
        md.push({ Id: ch.id, Val: val })
    }

    md.push({ Id: 7200, Val: battery })

    if (msg.snr !== undefined)
        md.push({ Id: 5400, Val: parseFloat(msg.snr) })
    if (msg.rssi !== undefined)
        md.push({ Id: 5500, Val: parseFloat(msg.rssi) })
    if (msg.dr?.spreadFactor !== undefined)
        md.push({ Id: 5200, Val: parseFloat(msg.dr.spreadFactor) })

    return { Dev: dev, ED: [], MD: md, TS: ts }
}

const mid = global.get("mid") || 0
let midOffset = 0

const out1 = values.slice(0, 4).some(v => v !== null)
    ? { ...msg, payload: { MID: mid + midOffset++, D: [buildDevice(Dev1, values.slice(0, 4), 0)] } }
    : null

const out2 = values.slice(4, 8).some(v => v !== null)
    ? { ...msg, payload: { MID: mid + midOffset++, D: [buildDevice(Dev2, values.slice(4, 8), 4)] } }
    : null

if (!out1) node.warn(`CH01 geen data - ${Dev1}`)
if (!out2) node.warn(`CH02 geen data - ${Dev2}`)

global.set("mid", mid + midOffset)

return [out1, out2]
